// Resolve a field that may be either a FR string (legacy) or {fr, en} object.
function localizeField(field, lang) {
  if (typeof field === "string") return field;
  if (field && typeof field === "object") return field[lang] || field.fr || field.en || "";
  return "";
}

// Localize a full case to a single language.
function localizeCase(c, lang) {
  return {
    ...c,
    title: localizeField(c.title, lang),
    context: localizeField(c.context, lang),
    prosecutionSpeech: localizeField(c.prosecutionSpeech, lang),
    defenseSpeech: localizeField(c.defenseSpeech, lang),
  };
}

// Lazy import getLang to avoid circular dep at parse time
function getLangSafe() {
  try {
    if (typeof localStorage !== "undefined") {
      const settings = JSON.parse(localStorage.getItem("leproces_settings") || "{}");
      if (settings.language) return settings.language;
    }
  } catch {}
  return "fr";
}

// Deterministic pick of one case from the pool, given category + seed (date string).
// Same seed always yields same case → daily case is reproducible across devices.
export function pickFallbackCase(category, seed = "") {
  const pool = FALLBACK_POOL[category] || FALLBACK_POOL.penal;
  const lang = getLangSafe();
  let picked;
  if (!seed) {
    picked = pool[Math.floor(Math.random() * pool.length)];
  } else {
    let h = 0;
    const key = `${seed}-${category}`;
    for (let i = 0; i < key.length; i++) { h = ((h << 5) - h) + key.charCodeAt(i); h |= 0; }
    picked = pool[Math.abs(h) % pool.length];
  }
  return localizeCase({ ...picked, category }, lang);
}

export function poolSize() {
  return Object.values(FALLBACK_POOL).reduce((acc, arr) => acc + arr.length, 0);
}

export function poolByCategory() {
  const out = {};
  for (const [k, v] of Object.entries(FALLBACK_POOL)) out[k] = v.length;
  return out;
}
